"""
mkt-christ layer — Acts chapters 4–6
Output: data/commentary/mkt-christ/acts.json
Run: python3 scripts/zc-christ-acts-4-6.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS_CH = {
"4": {
"1": "<p>The Sadducees' opposition to the apostles is rooted in their denial of resurrection — but the resurrection of Jesus is precisely the claim Peter has just made (3:15, 26). Jesus had predicted this opposition: 'they will hand you over to the local councils' (Matt 10:17); 'when they bring you before synagogues and rulers and authorities, do not be anxious about how you should defend yourself' (Luke 12:11). The arrest of the apostles for proclaiming resurrection in Jesus is the first fulfillment of the passion narrative's pattern extending into the community.</p>",
"2": "<p>The apostles are teaching 'the resurrection of the dead in Jesus' (tēn anastasin tēn ek nekrōn en tō Iēsou) — not resurrection as a general doctrine but specifically through Jesus as the firstfruit case. This is the precise christological claim that enrages the Sadducees and defines the early mission: resurrection has happened, concretely, in a named person, and this person is the basis for universal resurrection hope. The pattern of religious authority opposition to resurrection proclamation fulfills Jesus's warnings in Luke 21:12–15.</p>",
"3": "<p>The detention 'until the next day' because it was already evening reflects the same Sanhedrin procedural constraints that governed Jesus's trial — formal Jewish trials could not be conducted at night (m. Sanhedrin 4:1). The pattern of arrest → overnight detention → trial the next morning mirrors the passion narrative's structure. Peter and John stand where Jesus stood.</p>",
"4": "<p>Five thousand men believe despite the arrest — the multiplication of the community under opposition is the fulfillment of Jesus's parable of the sower (Luke 8:8, 'a hundredfold') and his prediction that 'the gates of hell shall not prevail' against the church (Matt 16:18). Opposition from the authorities accelerates rather than stops the mission's growth — a pattern that recurs throughout Acts and that Jesus had explicitly predicted ('they will persecute you from city to city,' Matt 23:34).</p>",
"5": "<p>The gathering of 'rulers, elders, and scribes' in Jerusalem is the same body that condemned Jesus — Annas, Caiaphas, and the high priestly family appear by name in v. 6. The apostles are arraigned before the identical tribunal. Luke's christological point is structural: what the Sanhedrin did to Jesus it is now doing to Jesus's witnesses, and the outcome will mirror the pattern — apparent defeat by institutional power, followed by divine vindication.</p>",
"6": "<p>Annas (still treated as the real high priest despite formal deposition by Rome) and Caiaphas (his son-in-law, current high priest) are the same pair who presided over Jesus's trial (Luke 22:54; John 18:13, 24). Their reappearance creates explicit continuity between the trial of Jesus and the trial of his witnesses. The same hands that handed Jesus to Pilate now interrogate the witnesses to his resurrection.</p>",
"7": "<p>'By what power or by what name did you do this?' — the Sanhedrin's question about authority echoes their challenge to Jesus in Luke 20:2 ('By what authority do you do these things?'). Jesus had answered with a counter-question and a veiled claim to divine authority; Peter will answer directly with a name — the name they condemned. The reversal is total: what they meant to suppress by crucifixion has become the operative power in Jerusalem.</p>",
"8": "<p>'Filled with the Holy Spirit' — Peter's Spirit-empowered defense fulfills Jesus's promise exactly: 'When they bring you before synagogues and rulers and authorities, do not be anxious about how you should defend yourself or what you should say, for the Holy Spirit will teach you in that very hour what you ought to say' (Luke 12:11–12; cf. Matt 10:19–20). The fulfillment is precise: the moment of Sanhedrin interrogation triggers the promised Spirit-speech.</p>",
"9": "<p>'If we are being examined today concerning a good deed done to a crippled man' — Peter frames the interrogation as absurdity: the authorities are investigating a healing. The framing is rhetorically powerful and theologically pointed: the Sanhedrin which condemned the one who healed on the Sabbath (Luke 6:6–11; 13:10–17) is now interrogating those who healed in his name. The pattern of authorities opposing the good that Jesus and his agents do is the fulfillment of Jesus's indictment: 'Woe to you lawyers, for you have taken away the key of knowledge; you did not enter yourselves, and you hindered those who were entering' (Luke 11:52).</p>",
"10": "<p>'By the name of Jesus Christ of Nazareth whom you crucified, whom God raised from the dead — by him this man is standing before you well.' The direct naming of the Sanhedrin's crime — 'whom you crucified' — echoes Peter's Pentecost sermon (2:23, 36) and is the christological center of the defense. The contrast 'you crucified / God raised' is the gospel's essential polarity: human rejection and divine vindication. The healed man standing is the visible evidence of resurrection power operative in Jesus's name.</p>",
"11": "<p>'This Jesus is the stone that was rejected by you, the builders, which has become the cornerstone.' Peter cites Psalm 118:22 — the same text Jesus cited in the temple (Luke 20:17: the stone the builders rejected becoming the cornerstone). Jesus had applied it to himself and to his rejection by the chief priests; Peter now applies it directly to the crucifixion and resurrection, with the Sanhedrin as the builders and Jesus as the rejected-then-vindicated stone. The christological argument is complete: the scripture predicted this rejection, the rejection has occurred, and the resurrection confirms the scripture's fulfillment.</p>",
"13": "<p>'Unlettered and ordinary men' (agrammatos kai idiōtai) — the Sanhedrin's assessment that Peter and John had no formal scribal training (no studied at the feet of a recognized rabbi) makes their eloquence inexplicable without the Spirit. 'They recognized that they had been with Jesus' — the perceived connection is not formal discipleship but the distinctive presence of one who walked with Jesus. The fulfilled word: 'A disciple is not above his teacher, but everyone when he is fully trained will be like his teacher' (Luke 6:40). Being with Jesus has transferred something to the disciples that scribal training alone cannot explain.</p>",
"14": "<p>The healed man standing with Peter and John renders the Sanhedrin's situation impossible — they cannot deny the sign without looking absurd before the city. The man's presence as a walking proof defeats the institutional power's ability to suppress the truth. Jesus had said, 'If these were silent, the very stones would cry out' (Luke 19:40) — and here, in a sense, a man who was formerly immobile is the irrefutable witness.</p>",
"15": "<p>The Sanhedrin's private deliberation mirrors their private deliberations about Jesus (Luke 22:66–71; Mark 14:55–64) — the judicial body again trying to manage a situation they cannot control. Their problem now is not Jesus (whom they killed) but the impossible persistence of his effects: a healed man, Spirit-filled disciples, and a growing community. The resurrection has made their solution to the Jesus problem worse than the problem itself.</p>",
"16": "<p>'We cannot deny it' — the Sanhedrin's internal confession of impotence is Luke's ironic climax. The ruling body of Israel acknowledges, in private, that they cannot suppress the evidence of Jesus's power. The institution that condemned Jesus as a false messiah who could not save himself now confesses it cannot stop what his name produces. The public suppression they choose (v. 17) in the face of private acknowledgment is the continuation of the bad faith that characterized the Passion.</p>",
"17": "<p>'That it may spread no further' — the Sanhedrin's agenda is containment: the same word (diaphtheirō, diaskorpizō) Jesus used for spreading. Their command mirrors Caiaphas's pragmatic judgment at Jesus's trial: 'It is better that one man die for the people' (John 11:49–50) — institutional management of theological danger through suppression. But Jesus had predicted the outcome: 'What you have whispered in private rooms shall be proclaimed on the housetops' (Luke 12:3).</p>",
"18": "<p>'Not to speak or teach at all in the name of Jesus' — the explicit prohibition is the empire of human authority attempting to silence the name. Jesus had said, 'Everyone who acknowledges me before men, I also will acknowledge before my Father' (Matt 10:32); the apostles' refusal to comply with this prohibition is the lived enactment of this acknowledgment. The prohibition creates the conditions for the confession of vv. 19–20.</p>",
"19": "<p>'Whether it is right in God's sight to listen to you rather than to God, you must judge' — Peter and John's response is the foundational statement of Christian civil disobedience: where human authority conflicts with divine command, divine authority supersedes. The formulation echoes Socrates' defense in the Apology (Plato, Apol. 29d: 'I shall obey God rather than you') — a point Luke's educated audience would recognize. But the christological grounding is different: Peter and John obey God because God has raised Jesus and commanded proclamation in his name.</p>",
"20": "<p>'We cannot but speak of what we have seen and heard' — eyewitness obligation as the grounds for disobedience. The 'we have seen and heard' is the epistemic foundation of apostolic witness (cf. 1 John 1:1–3; 2 Pet 1:16). Jesus had said, 'You are witnesses of these things' (Luke 24:48) — the witness commission overrides the Sanhedrin's suppression command because it comes from a higher authority.</p>",
"21": "<p>The release without punishment — because the city glorifies God for the healing — mirrors the partial protection Jesus enjoyed from the crowds during his Jerusalem ministry (Luke 19:47–48; 22:2). The people function as a check on the Sanhedrin's power, preventing official violence where the evidence of divine action is too public to suppress. The risen Lord's community operates under the same dynamic that protected Jesus himself: popular recognition of divine power constrains official hostility.</p>",
"22": "<p>The man was over forty years old — a detail that emphasizes the duration and certainty of his disability (congenital lame from birth, Acts 3:2, now over forty). No natural explanation could account for recovery from this condition. The age detail is Luke the physician's marker: this is medically impossible, which makes the theological claim unavoidable.</p>",
"23": "<p>The apostles' return to 'their own people' — the community of disciples — and their report of the Sanhedrin's words triggers a corporate prayer that is one of the most christologically dense passages in Acts. The community's response to institutional opposition is not political maneuvering but prayer grounded in scripture, specifically Psalm 2. The gathering mirrors Jesus's own post-temptation return to prayer and community.</p>",
"24": "<p>'Sovereign Lord, who made the heaven and the earth and the sea and everything in them' — the prayer opens with God as creator and sovereign (despota), a title that frames the Sanhedrin's authority as derivative and limited. The God who made everything is not threatened by the rulers of a small province; the prayer's opening establishes the perspective from which all that follows is interpreted. The community prays from the vantage point of divine sovereignty, not human anxiety.</p>",
"25": "<p>'Who through the mouth of our father David, your servant, said by the Holy Spirit: Why did the Gentiles rage, and the peoples plot in vain?' — Psalm 2:1–2 is cited as directly prophetic of the current moment. The attribution — through David, by the Holy Spirit — makes David the instrument and the Spirit the author, consistent with early Christian pneumatology of scripture (cf. 2 Pet 1:21). The 'nations raging' against the Lord's anointed is being fulfilled now, in Jerusalem, against Jesus and his witnesses.</p>",
"26": "<p>'The kings of the earth set themselves, and the rulers were gathered together, against the Lord and against his Anointed.' The prayer identifies Herod and Pilate as the 'kings and rulers' of Psalm 2 — Gentile and Jewish power collaborating against Jesus, God's Anointed (christos). The interpretive move is bold: a psalm about universal Gentile opposition to God's king is applied to the specific historical alliance of Rome and Jerusalem against Jesus. The cosmic frame makes Pilate and Herod actors in a drama written before their birth.</p>",
"27": "<p>'Herod and Pontius Pilate, along with the Gentiles and the peoples of Israel' — the specific historical agents of Jesus's crucifixion are named as the fulfillment of Psalm 2. The four-fold listing (Herod, Pilate, Gentiles, Israel) is comprehensive: all human power structures participated. This is not anti-Semitic targeting of Israel alone but a universal indictment — every human power structure aligned against God's anointed. The prayer names it clearly to frame the present opposition (Sanhedrin) as a continuation of the same alliance.</p>",
"28": "<p>'To do whatever your hand and your plan had predestined to take place' — the crucifixion was not a defeat but a divine plan fulfilled. God's prothesis (foreordained purpose) governed the actions of even those who opposed it: the same omnipotent sovereignty that created heaven and earth (v. 24) also ordained that the Anointed's rejection would accomplish the plan of redemption. The community's confidence in the face of opposition is grounded in this recognition: opposition itself is within God's providential scope.</p>",
"29": "<p>'And now, Lord, look upon their threats and grant to your servants to continue to speak your word with all boldness' — the prayer does not ask for removal of opposition but for courage within it. Jesus had prayed for his disciples in the same posture: 'I do not ask that you take them out of the world, but that you keep them from the evil one' (John 17:15). The request for parrēsia (boldness/freedom of speech) is specifically the Spirit-given courage Jesus promised for Sanhedrin appearances (Luke 12:11–12).</p>",
"30": "<p>'While you stretch out your hand to heal, and signs and wonders are performed through the name of your holy servant Jesus' — the prayer requests continued healing signs in Jesus's name. 'Holy servant' (ton hagion paida sou) echoes the Isaiah 42–53 Servant songs; the same title was used in 3:13, 26. The community prays for the continuation of the healing ministry Jesus modeled through his earthly life (Luke 4:18–19) now mediated through his risen name.</p>",
"31": "<p>'The place was shaken, and they were all filled with the Holy Spirit and continued to speak the word of God with boldness.' The immediate Spirit-filling and shaking of the place is a mini-Pentecost — the Spirit fulfills Jesus's promise in real time in response to prayer. The pattern: prayer → Spirit-filling → boldness → proclamation mirrors Acts 2 (prayer, 1:14 → Spirit, 2:4 → bold proclamation, 2:14). The Spirit does not come once but repeatedly as the community returns to prayer.</p>",
"32": "<p>'The full number of those who believed were of one heart and soul, and no one said that any of the things that belonged to him was his own, but they had everything in common.' The description of the early community's unity and sharing echoes the idealized vision of Israel's covenant community — the Deuteronomic hope that there be 'no poor among you' (Deut 15:4). Jesus had called his disciples away from possessiveness: 'sell your possessions and give to the needy' (Luke 12:33); 'any one of you who does not renounce all that he has cannot be my disciple' (Luke 14:33). The community is embodying the Sermon's ethics corporately.</p>",
"33": "<p>'With great power the apostles were giving their testimony to the resurrection of the Lord Jesus, and great grace was upon them all.' The resurrection testimony and the common life are inseparably linked: the community's generosity is the visible evidence of a people who believe death has been defeated. If Jesus is risen, possessions have a different status; if death is conquered, the hoarding impulse — fundamentally a death-anxiety response — is transformed. The 'great grace' (charis megalē) on the community is the overflow of the grace that raised Jesus.</p>",
"34": "<p>'There was not a needy person among them' — the fulfillment of Deuteronomy 15:4 LXX: 'there shall be no poor person among you.' The Deuteronomic promise was conditional on Israel's full obedience to the covenant; the early Christian community, constituted around the risen Lord and filled with the Spirit, fulfills it organically rather than by legal compliance. Jesus had promised: 'seek first the kingdom of God and his righteousness, and all these things will be added to you' (Matt 6:33); the community's provision for the poor is the kingdom's concrete manifestation.</p>",
"35": "<p>'Distribution was made to each as any had need' — the principle of distribution according to need rather than status or merit reflects the kingdom's inversions. Jesus's feeding miracles (Luke 9:12–17) had demonstrated this principle physically: everyone receives what they need. The apostles' mediating role in distribution mirrors Jesus's role in the feeding miracles where the disciples serve as intermediaries of divine provision.</p>",
"36": "<p>Joseph Barnabas — 'son of encouragement' (huios paraklēseōs) — is introduced precisely because his generosity will contrast with the Ananias-Sapphira deception in the next chapter. The naming of a specific generous giver before the narrative of false generosity serves to distinguish genuine from counterfeit covenant fidelity. Barnabas is a Levite of Cypriot origin — unexpected generosity from an unexpected quarter, consistent with Jesus's reversals of expectation about who embodies covenant faithfulness.</p>",
"37": "<p>Barnabas sells a field and brings the full proceeds. His act establishes the communal norm that Ananias will violate — the contrast is deliberate. The unreserved giving of Barnabas reflects the spirit of Jesus's call: 'sell all that you have and distribute to the poor, and you will have treasure in heaven, and come, follow me' (Luke 18:22). Whether the early community expected all property to be sold is debated, but Barnabas models the total-surrender posture Jesus modeled.</p>"
},
"5": {
"1": "<p>Ananias and Sapphira's deception immediately follows Barnabas's generosity — the juxtaposition is the narrative's interpretive frame. The story belongs to the pattern of covenant violation that follows covenant establishment: Genesis 3 follows Genesis 2; the golden calf follows Sinai; Achan (Josh 7) follows Jericho's victory. The first violation of the Spirit-filled community's integrity mirrors these OT paradigms. The community shaped by the resurrection is also the community where God's holiness operates with immediate consequence.</p>",
"2": "<p>'With his wife's knowledge, he kept back part of the proceeds and brought only a part and laid it at the apostles' feet.' The deception is about claiming total surrender while practicing partial surrender — the external posture of complete dedication with the internal reality of self-retention. Jesus had warned against exactly this: 'No one can serve two masters... You cannot serve God and money' (Matt 6:24). Ananias's lie is the embodied denial of Jesus's teaching on single-hearted devotion.</p>",
"3": "<p>'Ananias, why has Satan filled your heart to lie to the Holy Spirit and to keep back part of the proceeds?' Peter's diagnosis — satanic filling in contrast to the Spirit-filling of 4:31 — connects this to Jesus's binding of the strong man (Luke 11:21–22) and his identification of Satan as the father of lies (John 8:44, reflected in Luke's theology). The community constituted by the Spirit's Pentecostal filling is now being invaded by the counter-filling of deception. The battle is not sociological but spiritual.</p>",
"4": "<p>'You have not lied to men but to God' — the final line is the christological thunderclap: lying to the Holy Spirit (v. 3) is lying to God. The identification of the Spirit with God — implicit but unmistakable — underwrites the community's identity as a Spirit-inhabited temple (1 Cor 3:16–17). To deceive the community is to attempt to deceive the divine presence dwelling within it. This is precisely why Jesus warned that 'whoever blasphemes against the Holy Spirit will not be forgiven' (Luke 12:10) — the Spirit's indwelling makes the community's integrity a divine rather than merely human matter.</p>",
"5": "<p>Ananias falls down dead at Peter's words — without physical judgment being executed by humans. The immediate death is divine judgment, not apostolic execution. The pattern echoes God's judgment on Nadab and Abihu (Lev 10:1–3) — unauthorized approach to the holy — and Uzzah (2 Sam 6:6–7). The holiness of the risen Christ's community is not merely symbolic; the Spirit dwelling in it is the holy God. 'Great fear came upon all who heard' — the fear of God that wisdom begins with (Prov 9:10) returns to the community through this act of divine judgment.</p>",
"6": "<p>The young men (neoteroi) carry out Ananias's burial without ceremony or lengthy mourning — the rapidity and practicality of the burial reflects the gravity of the judgment. In Jewish practice, burial on the day of death was standard; the lack of extended mourning rituals marks this as a solemn rather than grievous loss. The community's response is awe, not grief — the judgment has served its purpose of revealing and protecting the community's holy character.</p>",
"7": "<p>Sapphira arrives three hours later, unaware — the narrative builds dramatic tension. Her independent appearance allows the test to be administered separately, confirming that the deception was not a momentary slip but a coordinated plan. The separate testing is consistent with legal procedure requiring independent witness; here it allows the reader to see that Sapphira's judgment is not collateral damage but her own moral choice confirmed.</p>",
"8": "<p>Peter's question — 'Tell me whether you sold the land for so much' — gives Sapphira the opportunity to repent and tell the truth. Her confirmation of the lie ('Yes, for so much') makes her complicit and equally guilty. Jesus had taught: 'For with the judgment you pronounce you will be judged' (Matt 7:2); Sapphira's deception receives the same judgment as her husband's, confirming the equality of their guilt. The test is merciful in its clarity; the grace not to lie is available and not taken.</p>",
"9": "<p>'How is it that you have agreed together to test the Spirit of the Lord?' — the deception as a 'testing' of the Spirit connects to Israel's testing of God in the wilderness (Exod 17:2, 7; Ps 95:8–9; 1 Cor 10:9). The community constituted by the new exodus is tempted to test God's Spirit as Israel tested God in the desert. Peter's announcement of Sapphira's immediate death — 'the feet of those who buried your husband are at the door, and they will carry you out' — is prophetic foreknowledge that mirrors Jesus's predictions of coming events with precise detail (Luke 21:20–24).</p>",
"10": "<p>Sapphira falls dead at Peter's feet — the same location where Ananias had placed his false gift. The feet of the apostle become the site of both false surrender and divine judgment. The parallel deaths confirm the narrative's theological point: the community of the risen Lord is a holy place where deception cannot survive. The symmetry is exact, and the symmetry is the message.</p>",
"11": "<p>'Great fear came upon the whole church and upon all who heard these things' — the first use of the word 'church' (ekklēsia) in Acts. The fear is the appropriate response to the presence of the holy: 'the fear of the LORD is the beginning of wisdom' (Prov 9:10). The church comes into explicit existence as a named entity precisely at the moment when its holiness is most dramatically demonstrated. The risen Christ's community is not a voluntary association of like-minded people but a holy people constituted by the Spirit of the Holy God.</p>",
"12": "<p>'Many signs and wonders were regularly done among the people by the hands of the apostles' — the ongoing miracle ministry fulfills Jesus's commission: 'Truly, truly, I say to you, whoever believes in me will also do the works that I do; and greater works than these will he do' (John 14:12). The 'greater works' are not individually greater miracles but the expanded scope of the mission — the same healing, delivering, restoring work of Jesus now operating through the apostles across Jerusalem and beyond.</p>",
"13": "<p>'None of the rest dared join them, but the people held them in high esteem.' The reverence-at-a-distance created by the Ananias-Sapphira episode means the community is not casually joined. Jesus had warned: 'count the cost' before following (Luke 14:28); the discipline of the Spirit has made membership in the community a serious commitment. The high esteem without casual enrollment mirrors Jesus's pattern of attracting crowds while warning disciples of the full cost.</p>",
"14": "<p>'And more than ever believers were added to the Lord, multitudes of both men and women' — the divine judgment of vv. 1–11 does not reduce the community but increases it. This is the resurrection logic: apparent defeat (death) produces growth. The holiness that killed Ananias and Sapphira is the same holiness that attracts sincere seekers. The community that demonstrates the real cost of membership paradoxically draws more members than the community that dilutes entry requirements.</p>",
"15": "<p>The sick carried into the streets so that Peter's shadow might fall on them echoes the healing ministry of Jesus where 'power came out from him and healed them all' (Luke 6:19). The shadow (skia) as vehicle of healing is not an endorsement of magical thinking but a testimony to the density of Jesus's presence in Peter's person — the anointing that rested on Jesus (Luke 4:18) has been transferred to his apostle. The multitudes who sought contact with Jesus (Luke 8:44) now seek analogous contact with Peter.</p>",
"16": "<p>The gathering from surrounding towns mirrors Jesus's widespread healing ministry (Luke 6:17–19; Mark 1:28) now operating through his apostles. 'They were all healed' — the comprehensiveness of the healing is the eschatological sign of Isaiah 35:5–6 (blind see, lame walk, deaf hear) that Jesus cited as evidence of his messianic identity (Luke 7:22). The healings are not isolated miracles but the continued dawn of the age of restoration that Jesus inaugurated.</p>",
"17": "<p>The Sadducees' second arrest of the apostles — 'filled with jealousy' (zēlou) — mirrors the first-century pattern: institutional religion opposes what it cannot control, especially when it attracts the popular devotion the institution covets. Jesus had identified this dynamic in the fig tree parable (Luke 13:6–9) and in his indictment of the teachers of the law who 'devour widows' houses' (Luke 20:47) while maintaining external piety. The Sadducees' jealousy is the spiritual pathology that also drove the high priests to hand Jesus over (Mark 15:10; Luke 23:12).</p>",
"18": "<p>The public prison (dēmosiai tērēsei) — the jail where the apostles are placed for the night mirrors Jesus's imprisonment before his trial. The pattern of the passion is being replicated: arrest → overnight confinement → trial → release (resurrection). The apostles are walking the passion road their master walked, which Jesus had predicted: 'If they persecuted me, they will also persecute you' (John 15:20).</p>",
"19": "<p>An angel of the Lord opens the prison and releases the apostles — divine intervention that mirrors the release from tomb on resurrection morning. The angel-at-the-prison echoes the angel-at-the-tomb (Luke 24:4; Matt 28:2–5). Jesus's resurrection was the paradigmatic divine opening of an otherwise sealed enclosure; the apostles' release extends the resurrection's liberating power into the mission's ongoing story. Where the risen Lord has broken death's prison, no other prison can hold his witnesses permanently.</p>",
"20": "<p>'Go and stand in the temple and speak to the people all the words of this Life' (pantas tous logous tēs zōēs tautēs) — the angel's instruction reestablishes the mission exactly where the Sanhedrin tried to terminate it: in the temple. 'Words of this Life' — the comprehensive gospel proclamation is characterized as 'Life' itself, not merely information about life. Jesus had said, 'I am the resurrection and the life' (John 11:25); the apostles' message embodies and mediates the Life that is Christ.</p>",
"21": "<p>The apostles enter the temple at dawn and teach — obedience to the angel's instruction before the Sanhedrin even convenes. When the Sanhedrin is assembling to try them, the apostles are already in the temple proclaiming. The irony is rich: the authorities think they have the apostles imprisoned; the apostles are free and teaching. The pattern of the empty tomb — the authorities think they have secured the situation; the reality is otherwise — replays.</p>",
"22": "<p>The officers sent to bring the prisoners find an empty jail — the 'empty tomb' of the apostles' story. 'They did not find them in the prison' echoes Luke 24:3 ('they did not find the body of the Lord Jesus'). The apostles' absence from where the authorities placed them is the narrative sign of resurrection power operating in the community: the same God who did not leave Jesus where they put him does not leave his witnesses where their opponents put them.</p>",
"23": "<p>The locked prison with guards at the doors but no prisoners inside — the physical impossibility of the situation without divine action is explicit. Guards at an empty cell. The physical security was complete; the divine release transcended it. This is the theological point about resurrection itself: all the human security measures (sealed tomb, guards, stones) were irrelevant to divine power. The apostles' release is a small-scale resurrection sign.</p>",
"24": "<p>The captain and chief priests are 'perplexed' (diēporoun) — the same word used for those who could not explain Jesus's resurrection (Luke 24:4). Institutional authority repeatedly encounters the effects of resurrection power and cannot explain them within its categories. The perplexity is not cognitive but existential: the categories by which human power operates (custody, trial, execution) have been made inadequate by the God who raises the dead.</p>",
"25": "<p>'The men whom you put in prison are standing in the temple and teaching the people' — the report that the apostles are in the very place where the authorities hoped to prevent them from teaching. The divine humor is characteristic of Luke's narrative: while the Sanhedrin debates what to do about the apostles, the apostles are doing precisely what the Sanhedrin forbade. Jesus's words echo: 'What I tell you in the dark, say in the light, and what you hear whispered, proclaim on the housetops' (Matt 10:27).</p>",
"26": "<p>'They went and brought them, but not by force, for they were afraid of being stoned by the people' — the apostles are escorted to the Sanhedrin, but the balance of power has shifted. The people, who revere the apostles, constrain the officials' ability to use violence. This is the same dynamic that had protected Jesus in the temple during Holy Week (Luke 19:47–48; 22:2). The community's public standing functions as a providential protection that Jesus had promised: 'you will be hated by all for my name's sake. But not a hair of your head will perish' (Luke 21:17–18).</p>",
"27": "<p>The Sanhedrin's formal reconvening mirrors the formal assembly that condemned Jesus. Peter and John stand before the same body, in the same city, on behalf of the same Jesus. The entire scene is the passion narrative extended into the community: the disciples do not escape the master's fate but walk through it as he walked through it, protected by the same divine sovereignty.</p>",
"28": "<p>'We strictly charged you not to teach in this name, yet here you have filled Jerusalem with your teaching, and you intend to bring this man's blood upon us.' The Sanhedrin's complaint that the apostles are 'filling Jerusalem' with the teaching is the fruition of Jesus's promise that the disciples would be his witnesses 'in Jerusalem' (1:8). Their complaint that the apostles are bringing 'this man's blood upon us' echoes their own words at Jesus's trial: 'His blood be on us and on our children' (Matt 27:25) — the charge returns as accusation.</p>",
"29": "<p>'We must obey God rather than men' — the principle stated first in 4:19–20 is now definitively articulated as the apostles' governing maxim. The apostolic disobedience is not political rebellion but theological obedience: the God who raised Jesus commands proclamation; human authorities command silence; the former supersedes the latter. Jesus had explicitly prepared the disciples for this choice: 'Do not fear those who kill the body but cannot kill the soul. Rather fear him who can destroy both soul and body in hell' (Matt 10:28).</p>",
"30": "<p>'The God of our fathers raised Jesus, whom you killed by hanging him on a tree.' The formula is precisely crafted: 'the God of our fathers' (ho theos tōn paterōn hēmōn) — the continuity with Israel's covenant God — juxtaposed with 'whom you killed by hanging on a tree' (kremasantes epi xylou). 'Hanging on a tree' invokes Deuteronomy 21:23 ('cursed is everyone who hangs on a tree,' cited by Paul in Gal 3:13) — the very Deuteronomic curse that made the crucifixion look like divine condemnation is here turned: God himself raised the one who bore the curse, vindicating rather than condemning him.</p>",
"31": "<p>'God exalted him at his right hand as Leader and Savior, to give repentance to Israel and forgiveness of sins.' 'Leader and Savior' (archēgon kai sōtēra) — archēgos (pioneer/leader) was used in 3:15 of the Author of Life; here paired with Savior (sōtēr), the term used for Jesus in Luke 2:11 (the angel's announcement to the shepherds). The exaltation to the right hand fulfills Psalm 110:1 (Jesus's own citation in Luke 20:42–43). The purpose of the exaltation is not merely Jesus's vindication but the gift of repentance and forgiveness — resurrection produces available grace.</p>",
"32": "<p>'And we are witnesses to these things, and so is the Holy Spirit, whom God has given to those who obey him.' The double witness — apostolic eyewitness and the Spirit's internal witness — fulfills the legal requirement of two or three witnesses (Deut 19:15). The Spirit as witness is the fulfillment of Jesus's promise: 'the Helper, the Holy Spirit, whom the Father will send in my name, he will teach you all things... he will bear witness about me' (John 14:26; 15:26). The apostles are not sole witnesses but co-witnesses with the Spirit of truth.</p>",
"33": "<p>'When they heard this, they were enraged and wanted to kill them' — the Sanhedrin's murderous rage mirrors the reaction to Jesus's claims at his trial (Luke 22:71 — 'What further testimony do we need?') and to his synagogue sermon in Nazareth (Luke 4:28–29 — 'they rose up and drove him out'). The word of God provokes murderous response in hardened hearts: Jesus had said, 'They hated me without a cause' (John 15:25), and the same causeless hatred now turns on his witnesses.</p>",
"34": "<p>Gamaliel's intervention — 'a Pharisee... held in honor by all the people' — introduces the most eminent rabbi of his generation (known from rabbinic tradition as Rabban Gamaliel I, teacher of Paul, Acts 22:3) as an unexpected moderating voice. His authority within the Sanhedrin constrains the Sadducean majority's desire for execution. The providential use of a Pharisee to protect the apostles from Sadducean violence is an ironic reversal — the party theologically opposed to the Sadducees becomes the instrument of the apostles' preservation.</p>",
"35": "<p>Gamaliel orders the apostles removed before speaking — the separation of the accused from the deliberation is proper Sanhedrin procedure. His address 'Men of Israel' parallels the apostles' own address formulas (2:14, 22; 3:12) — the shared rhetorical world of Second Temple Judaism in which both sides operate. Gamaliel's counsel is drawn from historical precedent rather than theological conviction about Jesus: a pragmatic argument for wait-and-see rather than premature suppression.</p>",
"36": "<p>Theudas — a previous messianic claimant who was killed and whose movement dissolved — is Gamaliel's first precedent. Josephus mentions a Theudas who led a movement to the Jordan c. AD 44–45 (Ant. 20.97–99), which is chronologically later than this speech, creating a historical puzzle. Luke may be referring to a different, earlier Theudas not mentioned in other sources, or the name (common) may refer to a different figure. The argument's logic is independent of the specific identification: movements die with their leader if they are merely human.</p>",
"37": "<p>Judas the Galilean — the founder of the Zealot movement at the time of the census under Quirinius (c. AD 6, mentioned in Luke 2:2) — is Gamaliel's second precedent: another movement that 'scattered' (dieskorpisthē) after its leader died. The implicit argument about Jesus's movement is then obvious: if Jesus is merely another failed messiah, his movement will dissolve naturally; the Sanhedrin need not act. What Gamaliel does not anticipate is that Jesus's movement claims he did not stay dead.</p>",
"38": "<p>'If this plan or this undertaking is of man, it will fail' — Gamaliel's theological criterion is sound even if his application is tentative. The history of Israel confirms it: human projects collapse; divine initiatives persist (Isa 46:10; Dan 2:44). The criterion Gamaliel articulates will be retrospectively confirmed by the church's persistence — no human movement of this kind has survived 2,000 years. Gamaliel's principle becomes the unwitting prophecy of the very reality he is cautiously evaluating.</p>",
"39": "<p>'But if it is of God, you will not be able to overthrow them. You might even be found opposing God!' (theomachoi) — the fear of being theomachus (God-fighter) was a recognizable Greek and Jewish category (cf. Euripides, Bacchae; 2 Macc 7:19). Gamaliel's warning is his greatest irony: the Sanhedrin has already crucified Jesus; the question is whether they will continue to fight the God who raised him. The warning is accurate without being salvific — Gamaliel protects the apostles without himself becoming a believer (so far as Acts records).</p>",
"40": "<p>The Sanhedrin's compromise — flogging the apostles and charging them not to speak in the name of Jesus — is a middle path between execution and release. The flogging (forty lashes minus one, the standard Jewish corporal punishment) is the first physical suffering the apostles endure, fulfilling Jesus's predictions: 'they will flog you in their synagogues' (Matt 10:17). The charge not to speak replicates the 4:18 charge; the apostles' response will replicate their 4:19–20 refusal.</p>",
"41": "<p>'Then they left the presence of the council, rejoicing that they were counted worthy to suffer dishonor for the name.' The apostles' joy in suffering is the direct fulfillment of the Beatitudes: 'Blessed are you when others revile you and persecute you... Rejoice and be glad, for your reward is great in heaven' (Matt 5:11–12; cf. Luke 6:22–23). 'The name' (tou onomatos) — the name of Jesus, the name above every name (Phil 2:9), which the Sanhedrin tried to suppress — is the explicit reason for the rejoicing. To suffer for this name is to participate in Jesus's own pattern of suffering followed by glory.</p>",
"42": "<p>'And every day, in the temple and from house to house, they did not cease teaching and preaching that the Christ is Jesus.' The final verse of the chapter is the summary of the unstoppable mission: every day, in every venue, the same proclamation continues. The Sanhedrin flogged them to silence the name; they proclaim the name with increased intensity. Jesus had promised, 'The gates of hell shall not prevail against it' (Matt 16:18) — the Sanhedrin is discovering this is literally true."
},
"6": {
"1": "<p>The Hellenist-Hebrew tension over the daily distribution of food mirrors the organizational challenges that accompany any growing movement but is also a prophetic test: will the community that just survived Ananias-Sapphira's internal deception now fracture along ethnic lines? The 'neglect' (paretheorounto) of Hellenist widows is not malicious but structural — the community's growth has outpaced its capacity to maintain equity. Jesus's concern for widows (Luke 7:11–15; 20:47; 21:1–4) makes their care a marker of the community's faithfulness.</p>",
"2": "<p>'It is not right that we should give up preaching the word of God to serve tables' — the Twelve's response is not a demotion of service but a recognition of the division of charisms. Jesus had modeled both: teaching crowds and feeding five thousand. The distinction the apostles draw is not between sacred and secular ministry but between two essential functions that require dedicated personnel. The 'word of God' (logos tou theou) as the apostles' primary responsibility reflects Jesus's priority: 'Do not work for the food that perishes, but for the food that endures to eternal life' (John 6:27).</p>",
"3": "<p>'Therefore, brothers, pick out from among you seven men of good repute, full of the Spirit and of wisdom' — the qualifications for the Seven mirror the qualifications Jesus set for his closest followers: Spirit-filled (Luke 4:1; Acts 1:8), wise (cf. Luke 21:15's promise of wisdom before accusers). The community selects rather than the Twelve appointing — consistent with Jesus's pattern of calling from within the community those already proven rather than importing leadership from outside.</p>",
"4": "<p>'But we will devote ourselves to prayer and to the ministry of the word' — the apostolic core is defined by the same two activities that characterized Jesus's own ministry: prayer (Luke 3:21; 5:16; 6:12; 9:18, 28; 11:1; 22:41–44) and teaching the word (Luke 4:43; 8:1; 20:1). The commissioning of the Seven frees the Twelve to practice what they saw Jesus practice. The community's leadership structure is rooted in the imitation of Christ's own ministry pattern.</p>",
"5": "<p>The proposal 'pleased the whole gathering' — community consensus in leadership selection fulfills the participatory model Jesus modeled in calling his disciples: he called them personally but from within the community's life. The Seven are all Greek-named (Stephen, Philip, Prochorus, Nicanor, Timon, Parmenas, Nicolaus) — a striking detail suggesting that the community addressed the Hellenist grievance by appointing primarily Hellenist leaders to the distribution role. Stephen is immediately qualified as 'full of faith and of the Holy Spirit.'</p>",
"6": "<p>'They set these before the apostles, and they prayed and laid their hands on them' — the laying on of hands (cheirotonia — literally 'stretching out hands') is the formal commissioning gesture from the OT (Num 27:18–23, Moses laying hands on Joshua) and will become the standard early Christian ordination rite (1 Tim 4:14; 5:22; 2 Tim 1:6). Jesus had laid hands on those he healed and blessed (Luke 13:13; 24:50); the apostles extend the same gesture to commission and empower their appointed servants.</p>",
"7": "<p>'And the word of God continued to increase, and the number of the disciples multiplied greatly in Jerusalem, and a great many of the priests became obedient to the faith.' Luke's growth summary notes especially the priests' conversion — the institutional gatekeepers of the Jerusalem temple cult becoming disciples of Jesus, whose body replaces the temple as God's dwelling (John 2:21; Eph 2:21–22). Priestly conversion is the sign that the temple establishment itself is being undone from within.</p>",
"8": "<p>Stephen — already identified as 'full of faith and of the Holy Spirit' (v. 5) — is now described as 'full of grace and power' performing 'great wonders and signs among the people.' Stephen's ministry profile exactly mirrors that of Jesus (Luke 4:14, 'in the power of the Spirit') and the apostles (Acts 2:43, 'wonders and signs done through the apostles'). The Seven were commissioned for table service; Stephen immediately functions as a Spirit-empowered proclaimer and miracle-worker. The Spirit's gifts distribute beyond administrative assignments.</p>",
"9": "<p>Opposition arises from Hellenist synagogues — the same diaspora communities Stephen himself likely came from (as a Hellenist Jew turned Christ-follower). The Synagogue of the Freedmen (Libertinōn — probably descendants of Jews taken captive by Pompey in 63 BC and later freed in Rome) and those from Cyrene, Alexandria, Cilicia, and Asia represent the international Jewish diaspora in Jerusalem. Cilician Jews — Paul's home region — may include Paul himself (cf. 7:58; 22:3). The opposition patterns Jesus's: rejected by those closest to him religiously and geographically.</p>",
"10": "<p>'They could not withstand the wisdom and the Spirit with which he was speaking' — the fulfillment of Jesus's promise exactly: 'I will give you a mouth and wisdom which none of your adversaries will be able to withstand or contradict' (Luke 21:15). Stephen's opponents are not intellectually inferior; they are facing the Spirit-given wisdom that Jesus promised his witnesses would receive. Their inability to refute him drives them to the only remaining option: false testimony.</p>",
"11": "<p>The secret instigation of false witnesses — men who claimed to have heard blasphemous words against Moses and God — precisely mirrors the false witnesses at Jesus's trial who claimed he said he would destroy the temple (Matt 26:60–61; Mark 14:57–58). The pattern of false accusation — unable to defeat the argument, manufacture a charge — is the passion narrative replayed. Stephen is walking the road Jesus walked.</p>",
"12": "<p>The stirring up of 'the people and the elders and the scribes' — three constituencies that also appear in Jesus's passion accounts (Luke 22:52–53, 66) — confirms the parallel. The seizure and bringing to the Sanhedrin is the apostolic arrest pattern of Acts 4–5 applied now to Stephen individually. The Sanhedrin is about to conduct its third major trial of a Jesus-follower in Acts, each one more intense than the last.</p>",
"13": "<p>The false witnesses' charge — that Stephen never ceases to speak against the holy place and the law — mirrors the charge against Jesus at his trial: that he had claimed he would destroy the temple made with hands and build another in three days (Mark 14:58). The accusation about the temple is false as stated but contains a truth the accusers cannot understand: Jesus had predicted the temple's destruction (Luke 21:5–6) and declared himself the new locus of God's presence (John 2:19–21). Stephen will expound this in ch. 7.</p>",
"14": "<p>'We have heard him say that this Jesus of Nazareth will destroy this place and will change the customs that Moses delivered to us' — the charge of both temple-destruction and law-change are the two most explosive accusations possible in Second Temple Judaism. They are also theologically accurate descriptions of what Jesus had done: inaugurated the new covenant that relativized the temple and fulfilled the law by fulfilling its trajectory (Matt 5:17; Heb 8:13). The false witnesses articulate a truth they mean as an accusation.</p>",
"15": "<p>'And gazing at him, all who sat in the Sanhedrin saw that his face was like the face of an angel.' The radiant face of Stephen before the Sanhedrin echoes Moses's shining face after the divine encounter at Sinai (Exod 34:29–35) — the reference that Stephen will develop extensively in his speech (Acts 7:30–35, 38, 44). Stephen's face is the anticipation of the glory he will see: 'behold, I see the heavens opened, and the Son of Man standing at the right hand of God' (7:56). He is already partaking in the glory of the risen Christ before the vision is given."
}
}

def main():
    existing = load_comm('mkt-christ', 'acts')
    merge_comm(existing, ACTS_CH)
    save_comm('mkt-christ', 'acts', existing)
    for ck in ['4', '5', '6']:
        count = len(existing.get(ck, {}))
        print(f'Acts {ck}: {count} verses.')

if __name__ == '__main__':
    main()
